import java.util.Scanner;
import org.owasp.encoder.Encode;

public class XSSSecureExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Sanitize user input using OWASP Java Encoder library
        String sanitizedInput = Encode.forHtml(userInput);

        String welcomeMessage = "Welcome, " + sanitizedInput + "!";

        // Output the sanitized welcome message
        System.out.println("<h1>" + welcomeMessage + "</h1>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
